using System; using System.Collections.Generic; using System.Linq; using GestaoEmprestimos.Domain.Entities; namespace GestaoEmprestimos.Application; public class EmprestimoService { private readonly List<Aluno> _alunos = new() { new Aluno("RA001", "Maria Silva"), new Aluno("RA002", "Joao Souza") }; private readonly List<ProdutoMoc> _produtos = new(); private readonly List<EmprestimoMoc> _emprestimos = new(); public List<Aluno> Alunos => _alunos; public List<string> Professores { get; } = new() { "Dr. Carlos Alberto", "Prof. Ana Beatriz" }; public List<Material> Materiais => _produtos.Select(p => new Material(int.TryParse(p.Codigo, out int idVal) ? idVal : 1, p.Nome, default, p.Codigo, p.Descricao, "", p.Quantidade)).ToList(); public List<EmprestimoMoc> Emprestimos => _emprestimos; public void CadastrarEstudante(string ra, string nome) => _alunos.Add(new Aluno(ra, nome)); public void CadastrarEstudante(object estudante, string nome = null) => _alunos.Add(new Aluno(Guid.NewGuid().ToString().Substring(0,8), nome ?? "Estudante")); public void CadastrarProfessor(string nome) => Professores.Add(nome); public void CadastrarProfessor(object professor, string nome = null) => Professores.Add(nome ?? "Professor"); public void CadastrarMaterial(object material, string nome = null) {} public void CadastrarMaterialCompleto(string titulo, string codigo, string descricao, int qtd) { var p = _produtos.FirstOrDefault(x => x.Codigo == codigo); if (p != null) { p.Quantidade += qtd; } else { _produtos.Add(new ProdutoMoc { Codigo = codigo, Nome = titulo, Descricao = string.IsNullOrEmpty(descricao) ? "Geral" : descricao, Quantidade = qtd }); } } public List<Material> ListarMateriais() => Materiais; public List<Aluno> ListarEstudantes() => _alunos; public List<EmprestimoMoc> ListarEmprestimos() => _emprestimos; public string RealizarSolicitacao(Aluno aluno, string professor, Material m) { var prod = _produtos.FirstOrDefault(x => x.Codigo == m.Id.ToString() && x.Quantidade > 0); if (prod == null) return "Erro: Material indisponivel no estoque."; _emprestimos.Add(new EmprestimoMoc { Id = Guid.NewGuid().ToString().Substring(0,5), Aluno = aluno, Professor = professor, Material = m, DataRetirada = DateTime.Now, PrazoDevolucao = DateTime.Now.AddDays(7), Situacao = "Solicitado" }); return "Solicitacao realizada com sucesso! Aguardando aprovacao."; } public void RealizarEmprestimo(object p1, object p2 = null, object p3 = null, object p4 = null, object p5 = null) {} public void FinalizarEmprestimo(object emprestimo) {} public void AprovarMovimentacao(EmprestimoMoc emp) { emp.Situacao = "Aprovado"; var prod = _produtos.FirstOrDefault(x => x.Codigo == emp.Material.Id.ToString()); if (prod != null) { prod.Quantidade--; } } public void DevolverMovimentacao(EmprestimoMoc emp) { emp.Situacao = "Devolvido"; emp.Avaliacao = "Material Adequado e Acessivel"; var prod = _produtos.FirstOrDefault(x => x.Codigo == emp.Material.Id.ToString()); if (prod != null) { prod.Quantidade++; } } } public class ProdutoMoc { public string Codigo { get; set; } = ""; public string Nome { get; set; } = ""; public string Descricao { get; set; } = ""; public int Quantidade { get; set; } } public class EmprestimoMoc { public string Id { get; set; } = ""; public Aluno Aluno { get; set; } = new Aluno("PADRAO","Sem Aluno"); public string Professor { get; set; } = ""; public Material Material { get; set; } = new Material(1,"",default,"","","",1); public DateTime DataRetirada { get; set; } public DateTime PrazoDevolucao { get; set; } public string Situacao { get; set; } = ""; public string Avaliacao { get; set; } = ""; }
